<template>
    <div class="padding-t_10" id="reportstabsdata">
        <div class="left-menu-tab new_tab">
            <div class="col-md-12 p-0">
                <div class="theme-primary partition">
                    <span class="p-name text-white">Field Service Management Reports</span>
                </div>
            </div>            
            <div class="mt-2" id="divscrollsetuptabs" style="max-height: 700px">
                <ul class="nav nav-pills flex-column left-tab responivecustomtab lefttabiconfix lefttabflexible" id="upper" role="tablist">
                    <li v-for="(tab, index) in filteredTabs" :key="index">
                        <a class="nav-link left-menu" :data-toggle="'#' + tab.id" :class="{ active: activeKey === tab.index }" @click="activateTab(tab.index)">
                            <i :class="tab.icon" aria-hidden="true"></i>{{ $t(tab.name) }}
                        </a>
                    </li>
                </ul>
            </div>
        </div>
    
        <!-- right-content here -->
        <div class="right-content">
            <loader :isVisible="isLoading"></loader>
            <div class="col-md-12 p-0">
                <div class="theme-primary partition" style="overflow: visible">
                    <span class="p-name text-white" id="spnreporttext">{{
                this.$t(activeTabName)
              }}</span>
                </div>
            </div>
            <div class="col-md-12 p-0">
                <div class="tab-content" id="myTabContent">
                    <div class="expand-list">
                        <a href="javascript:;" class="expand-list-btn justify-content-center align-items-center">
                            <i class="icon-solid arrow-solid-left text-white" style="font-size: 9pt"></i>
                        </a>
                    </div>
                    <div id="FieldServiceTicketReport" class="tab-pane" :class="{ 'active show': activeKey == 0 }" v-if="activeKey == 0">
                        <FieldServiceTicketReport></FieldServiceTicketReport>
                    </div>
                    <div id="Researcher" class="tab-pane" :class="{ 'active show': activeKey == 1 }" v-if="activeKey == 1">
                        <Researcher></Researcher>
                    </div>
                    <div id="SMSLogReport" class="tab-pane" :class="{ 'active show': activeKey == 2 }" v-if="activeKey == 2">
                        <SMSLogReport></SMSLogReport>
                    </div>
                    <div id="TicketLogReport" class="tab-pane" :class="{ 'active show': activeKey == 3 }" v-if="activeKey == 3">
                        <TicketLogReport></TicketLogReport>
                    </div>
                    <div id="TicketStatusReport" class="tab-pane" :class="{ 'active show': activeKey == 4 }" v-if="activeKey == 4">
                        <TicketStatusReport></TicketStatusReport>
                    </div>
                    <div id="TicketWorkOrderReport" class="tab-pane" :class="{ 'active show': activeKey == 5 }" v-if="activeKey == 5">
                        <TicketWorkOrderReport></TicketWorkOrderReport>
                    </div>
                    <div id="UserAliasreport" class="tab-pane" :class="{ 'active show': activeKey == 6 }" v-if="activeKey == 6">
                        <UserAliasreport></UserAliasreport>
                    </div>
                    <div id="LeavePending" class="tab-pane" :class="{ 'active show': activeKey == 7 }" v-if="activeKey == 7">
                        <LeavePending></LeavePending>
                    </div>
                    <div id="LeaveApproved" class="tab-pane" :class="{ 'active show': activeKey == 8 }" v-if="activeKey == 8">
                        <LeaveApproved></LeaveApproved>
                    </div>
                    <div id="Hiring" class="tab-pane" :class="{ 'active show': activeKey == 9 }" v-if="activeKey == 9">
                        <Hiring></Hiring>
                    </div>
                </div>
            </div>
        </div>
        <!-- right-content End here -->
    </div>
    </template>
    
    <script>
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
    import FieldServiceTicketReport from "../../views/FSMReport/FieldServiceTicketReport.vue";
    import Researcher from "../../views/FSMReport/Researcher.vue";
    import SMSLogReport from "../../views/FSMReport/SMSLogReport.vue";
    import TicketLogReport from "../../views/FSMReport/TicketLogReport.vue";
    import TicketStatusReport from "../../views/FSMReport/TicketStatusReport.vue";
    import TicketWorkOrderReport from "../../views/FSMReport/TicketWorkOrderReport.vue";

    
    export default {
        components: {
            FieldServiceTicketReport,
            Researcher,
            SMSLogReport,
            TicketLogReport,
            TicketStatusReport,
            TicketWorkOrderReport
         },
        data() {
            return {
                activeKey: 0,
                tabNames: [
                    "Field Service Ticket Report",
                    "Researcher Report",
                    "SMS Log Report",
                    "Ticket Log Report",
                    "Ticket Status Report",
                    "Ticket Work Order Report"
                ],
                searchQuery: "",
            };
        },
        mounted() {
            // Check for tab in route after component is mounted
            this.initializeTabFromRoute();
        },
        
        watch: {
            // Watch for route changes (e.g., browser back/forward)
            '$route'(to, from) {
                if (to.path === '/FSMReport/Index') {
                    this.initializeTabFromRoute();
                }
            }
        },
        created:function(){
            
        },
        computed: {
        filteredTabs() {
            if (!this.searchQuery) {           
                return this.tabNames.map((name, index) => ({
                    name,
                    index,
                    icon: this.getTabIcon(name)
                }));
            }
            const query = this.searchQuery.toLowerCase();
            const filtered = this.tabNames
                .map((name, index) => ({
                    name,
                    index,
                    icon: this.getTabIcon(name)
                }))
                .filter(tab => this.$t(tab.name).toLowerCase().includes(query));
    
            if (query.trim() !== '' && filtered.length === 0) {           
                return [{ name: 'No tabs found for "' + this.searchQuery + '"', index: -1, icon: 'no-icon' }];
            }
    
            return filtered;
        },
        activeTabName() {
            return this.tabNames[this.activeKey]; // Returns the name of the currently active tab
        }
    },
    
        methods: {
            getTabIcon(name) {
                switch (name) {
                    case "Field Service Ticket Report":
                        return "fa fa-print";
                    case "Researcher Report":
                        return "fa fa-search";
                    case "SMS Log Report":
                        return "fa fa-commenting";
                    case "Ticket Log Report":
                        return "fa fa-ticket";
                    case "Ticket Status Report":
                        return "fa fa-list-alt";
                    case "Ticket Work Order Report":
                        return "fa fa-file-text-o";
                    default:
                        return "";
                }
            },
            activateTab(index) {
                if (index < 0 || index >= this.tabNames.length) {
                    return; // Invalid index
                }
                
                this.activeKey = index;
                
                // Update URL with tab name
                const tabName = this.tabNames[index];
                const encodedTabName = this.encodeTabName(tabName);
                
                // Only update route if it's different to avoid unnecessary navigation
                if (this.$route.query.tab !== encodedTabName) {
                    this.$router.push({
                        path: '/FSMReport/Index',
                        query: { tab: encodedTabName }
                    }).catch(err => {
                        // Ignore navigation duplicated errors
                        if (err.name !== 'NavigationDuplicated') {
                            console.error('Navigation error:', err);
                        }
                    });
                }
            },
            
            // Encode tab name for URL (replace spaces and special chars)
            encodeTabName(tabName) {
                return encodeURIComponent(tabName);
            },
            
            // Decode tab name from URL
            decodeTabName(encodedName) {
                try {
                    return decodeURIComponent(encodedName);
                } catch (e) {
                    return encodedName; // Return as-is if decoding fails
                }
            },
            
            // Initialize tab from route query parameter
            initializeTabFromRoute() {
                if (this.tabNames.length === 0) {
                    return; // Wait for tabs to load
                }
                
                const tabParam = this.$route.query.tab;
                
                if (tabParam) {
                    const decodedTabName = this.decodeTabName(tabParam);
                    const tabIndex = this.tabNames.findIndex(name => name === decodedTabName);
                    
                    if (tabIndex !== -1) {
                        // Tab found, activate it
                        this.activeKey = tabIndex;
                    } else {
                        // Tab not found, fallback to first tab and update URL
                        this.activeKey = 0;
                        const firstTabName = this.encodeTabName(this.tabNames[0]);
                        this.$router.replace({
                            path: '/FSMReport/Index',
                            query: { tab: firstTabName }
                        }).catch(() => {});
                    }
                } else {
                    // No tab in URL, activate first tab and add it to URL
                    if (this.tabNames.length > 0) {
                        this.activeKey = 0;
                        const firstTabName = this.encodeTabName(this.tabNames[0]);
                        this.$router.replace({
                            path: '/FSMReport/Index',
                            query: { tab: firstTabName }
                        }).catch(() => {});
                    }
                }
            },
        },
    };
    </script>
    